// eximActionTypeFindSubmatch returns captured groups for the regex `^(\S{16})\s([<=\*][=>\*])\s(\S+.*)$`.
// Returns nil if the input does not match.
// Index 0 is the entire match, indices 1..N are capture groups.
func eximActionTypeFindSubmatch(input string) []string {
	if !eximActionTypeMatch(input) {
		return nil
	}
	// NFA instruction types
	const (
		opRune      = 0
		opRune1     = 1
		opRuneAny   = 2
		opRuneAnyNL = 3
		opAlt       = 4
		opCapture   = 5
		opMatch     = 6
		opNop       = 7
		opFail      = 8
		opEmpty     = 9
	)

	type nfaInst struct {
		op    int
		out   int
		arg   int
		runes []rune
	}

	prog := []nfaInst{
		/* 0 */ {op: opFail, out: 0, arg: 0},
		/* 1 */ {op: opEmpty, out: 2, arg: 4},
		/* 2 */ {op: opCapture, out: 3, arg: 2},
		/* 3 */ {op: opRune, out: 4, arg: 0, runes: []rune{0, 8, 11, 11, 14, 31, 33, 1114111}},
		/* 4 */ {op: opRune, out: 5, arg: 0, runes: []rune{0, 8, 11, 11, 14, 31, 33, 1114111}},
		/* 5 */ {op: opRune, out: 6, arg: 0, runes: []rune{0, 8, 11, 11, 14, 31, 33, 1114111}},
		/* 6 */ {op: opRune, out: 7, arg: 0, runes: []rune{0, 8, 11, 11, 14, 31, 33, 1114111}},
		/* 7 */ {op: opRune, out: 8, arg: 0, runes: []rune{0, 8, 11, 11, 14, 31, 33, 1114111}},
		/* 8 */ {op: opRune, out: 9, arg: 0, runes: []rune{0, 8, 11, 11, 14, 31, 33, 1114111}},
		/* 9 */ {op: opRune, out: 10, arg: 0, runes: []rune{0, 8, 11, 11, 14, 31, 33, 1114111}},
		/* 10 */ {op: opRune, out: 11, arg: 0, runes: []rune{0, 8, 11, 11, 14, 31, 33, 1114111}},
		/* 11 */ {op: opRune, out: 12, arg: 0, runes: []rune{0, 8, 11, 11, 14, 31, 33, 1114111}},
		/* 12 */ {op: opRune, out: 13, arg: 0, runes: []rune{0, 8, 11, 11, 14, 31, 33, 1114111}},
		/* 13 */ {op: opRune, out: 14, arg: 0, runes: []rune{0, 8, 11, 11, 14, 31, 33, 1114111}},
		/* 14 */ {op: opRune, out: 15, arg: 0, runes: []rune{0, 8, 11, 11, 14, 31, 33, 1114111}},
		/* 15 */ {op: opRune, out: 16, arg: 0, runes: []rune{0, 8, 11, 11, 14, 31, 33, 1114111}},
		/* 16 */ {op: opRune, out: 17, arg: 0, runes: []rune{0, 8, 11, 11, 14, 31, 33, 1114111}},
		/* 17 */ {op: opRune, out: 18, arg: 0, runes: []rune{0, 8, 11, 11, 14, 31, 33, 1114111}},
		/* 18 */ {op: opRune, out: 19, arg: 0, runes: []rune{0, 8, 11, 11, 14, 31, 33, 1114111}},
		/* 19 */ {op: opCapture, out: 20, arg: 3},
		/* 20 */ {op: opRune, out: 21, arg: 0, runes: []rune{9, 10, 12, 13, 32, 32}},
		/* 21 */ {op: opCapture, out: 22, arg: 4},
		/* 22 */ {op: opRune, out: 23, arg: 0, runes: []rune{42, 42, 60, 61}},
		/* 23 */ {op: opRune, out: 24, arg: 0, runes: []rune{42, 42, 61, 62}},
		/* 24 */ {op: opCapture, out: 25, arg: 5},
		/* 25 */ {op: opRune, out: 26, arg: 0, runes: []rune{9, 10, 12, 13, 32, 32}},
		/* 26 */ {op: opCapture, out: 27, arg: 6},
		/* 27 */ {op: opRune, out: 28, arg: 0, runes: []rune{0, 8, 11, 11, 14, 31, 33, 1114111}},
		/* 28 */ {op: opAlt, out: 27, arg: 30},
		/* 29 */ {op: opRuneAnyNL, out: 30, arg: 0, runes: []rune{0, 9, 11, 1114111}},
		/* 30 */ {op: opAlt, out: 29, arg: 31},
		/* 31 */ {op: opCapture, out: 32, arg: 7},
		/* 32 */ {op: opEmpty, out: 33, arg: 8},
		/* 33 */ {op: opMatch, out: 0, arg: 0},
	}
	startPC := 1

	// Thompson NFA simulation with capture tracking
	type thread struct {
		pc   int
		caps [8]int
	}

	addThread := func(list []thread, pc int, caps [8]int, pos int) []thread {
		visited := make(map[int]bool)
		var stack []thread
		stack = append(stack, thread{pc: pc, caps: caps})
		for len(stack) > 0 {
			t := stack[len(stack)-1]
			stack = stack[:len(stack)-1]
			if t.pc < 0 || t.pc >= len(prog) || visited[t.pc] {
				continue
			}
			visited[t.pc] = true
			inst := &prog[t.pc]
			switch inst.op {
			case opAlt:
				stack = append(stack, thread{pc: inst.arg, caps: t.caps})
				stack = append(stack, thread{pc: int(inst.out), caps: t.caps})
			case opNop, opEmpty:
				stack = append(stack, thread{pc: int(inst.out), caps: t.caps})
			case opCapture:
				newCaps := t.caps
				if inst.arg < 8 {
					newCaps[inst.arg] = pos
				}
				stack = append(stack, thread{pc: int(inst.out), caps: newCaps})
			default:
				list = append(list, t)
			}
		}
		return list
	}

	runeMatch := func(inst *nfaInst, r rune) bool {
		switch inst.op {
		case opRuneAny:
			return true
		case opRuneAnyNL:
			return r != '\n'
		case opRune1:
			if len(inst.runes) > 0 && inst.runes[0] == r {
				return true
			}
			return false
		case opRune:
			for i := 0; i < len(inst.runes)-1; i += 2 {
				if r >= inst.runes[i] && r <= inst.runes[i+1] {
					return true
				}
			}
			if len(inst.runes)%2 == 1 {
				if r == inst.runes[len(inst.runes)-1] {
					return true
				}
			}
			return false
		}
		return false
	}

	var initCaps [8]int
	for i := range initCaps {
		initCaps[i] = -1
	}
	initCaps[0] = 0 // group 0 start = beginning of input

	current := addThread(nil, startPC, initCaps, 0)

	for i, r := range input {
		var next []thread
		for _, t := range current {
			inst := &prog[t.pc]
			if runeMatch(inst, r) {
				next = addThread(next, int(inst.out), t.caps, i+len(string(r)))
			}
		}
		current = next
	}

	for _, t := range current {
		if t.pc < len(prog) && prog[t.pc].op == opMatch {
			t.caps[1] = len(input) // group 0 end
			result := make([]string, 4)
			for g := 0; g < 4; g++ {
				s, e := t.caps[g*2], t.caps[g*2+1]
				if s >= 0 && e >= 0 && s <= len(input) && e <= len(input) {
					result[g] = input[s:e]
				}
			}
			return result
		}
	}
	return nil
}

