	addThread := func(list []thread, pc int, caps [20]int, pos int) []thread {
		visited := make(map[int]bool)
		var stack []thread
		stack = append(stack, thread{pc: pc, caps: caps})
		for len(stack) > 0 {
			t := stack[len(stack)-1]
			stack = stack[:len(stack)-1]
			if t.pc < 0 || t.pc >= len(prog) || visited[t.pc] {
				continue
			}
			visited[t.pc] = true
			inst := &prog[t.pc]
			switch inst.op {
			case opAlt:
				stack = append(stack, thread{pc: inst.arg, caps: t.caps})
				stack = append(stack, thread{pc: int(inst.out), caps: t.caps})
			case opNop, opEmpty:
				stack = append(stack, thread{pc: int(inst.out), caps: t.caps})
			case opCapture:
				newCaps := t.caps
				if inst.arg < 20 {
					newCaps[inst.arg] = pos
				}
				stack = append(stack, thread{pc: int(inst.out), caps: newCaps})
			default:
				list = append(list, t)
			}
		}
		return list
	}

	runeMatch := func(inst *nfaInst, r rune) bool {
		switch inst.op {
		case opRuneAny:
			return true
		case opRuneAnyNL:
			return r != '\n'
		case opRune1:
			if len(inst.runes) > 0 && inst.runes[0] == r {
				return true
			}
			return false
		case opRune:
			for i := 0; i < len(inst.runes)-1; i += 2 {
				if r >= inst.runes[i] && r <= inst.runes[i+1] {
					return true
				}
			}
			if len(inst.runes)%2 == 1 {
				if r == inst.runes[len(inst.runes)-1] {
					return true
				}
			}
			return false
		}
		return false
	}

